func (s *GameServer) handleGiveItems(client *Client, args []string) error {
	if len(args) < 2 {
		return fmt.Errorf("usage: /giveitems <username> <item>")
	}
	
	targetUsername := args[0]
	item := args[1]
	
	s.mu.RLock()
	defer s.mu.RUnlock()
	
	for c := range s.clients {
		if c.username == targetUsername {
			message := fmt.Sprintf("You have been given item: %s", item)
			c.conn.Write([]byte(message + "\n"))
			return nil
		}
	}
	
	return fmt.Errorf("user %s not found", targetUsername)
}

func (s *GameServer) handleHelp(client *Client, args []string) error {
	var helpText strings.Builder
	helpText.WriteString("Available commands:\n")
	
	s.mu.RLock()
	defer s.mu.RUnlock()
	
	for _, cmd := range s.commands {
		if cmd.MinRole <= client.role {
			helpText.WriteString(fmt.Sprintf("  %s - %s\n", cmd.Name, cmd.Description))
		}
	}
	
	client.conn.Write([]byte(helpText.String()))
	return nil
}

func (s *GameServer) parseCommand(message string) (string, []string, bool) {
	if !strings.HasPrefix(message, "/") {
		return "", nil, false
	}
	
	parts := strings.Fields(message)
	if len(parts) == 0 {
		return "", nil, false
	}
	
	command := strings.ToLower(parts[0])
	args := parts[1:]
	
	return command, args, true
}

func (s *GameServer) validateRole(client *Client, requiredRole UserRole) bool {
	client.mu.RLock()
	defer client.mu.RUnlock()
	return client.role >= requiredRole
}

func (s *GameServer) handleClient(client *Client) {
	defer func() {
		s.mu.Lock()
		delete(s.clients, client)
		s.mu.Unlock()
		client.conn.Close()
	}()
	
	scanner := bufio.NewScanner(client.conn)
	
	for scanner.Scan() {
		message := scanner.Text()
		
		if strings.HasPrefix(message, "/") {
			command, args, isCommand := s.parseCommand(message)
			if !isCommand {
				continue
			}
			
			cmd, exists := s.commands[command]
			if !exists {
				client.conn.Write([]byte("Unknown command\n"))
				continue
			}
			
			if !s.validateRole(client, cmd.MinRole) {
				client.conn.Write([]byte("Insufficient permissions\n"))
				continue
			}
			
			if err := cmd.Handler(client, args); err != nil {
				client.conn.Write([]byte(fmt.Sprintf("Error: %v\n", err)))
			}
		} else {
			// Broadcast chat message
			s.broadcastMessage(client.username, message)
		}
	}
}

func (s *GameServer) broadcastMessage(username, message string) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	
	for client := range s.clients {
		client.mu.RLock()
		msg := fmt.Sprintf("<%s>: %s\n", username, message)
		client.conn.Write([]byte(msg))
		client.mu.RUnlock()
	}
}

func (s *GameServer) addClient(conn net.Conn, username string, role UserRole) {
	client := &Client{
		conn:     conn,
		username: username,
		role:     role,
	}
	
	s.mu.Lock()
	s.clients[client] = true
	s.mu.Unlock()
	
	go s.handleClient(client)
}

func (s *GameServer) Start(addr string) error {
	listener, err := net.Listen("tcp", addr)
	if err != nil {
		return err
	}
	defer listener.Close()
	
	fmt.Printf("Game server listening on %s\n", addr)
	
	for {
		conn, err := listener.Accept()
		if err != nil {
			select {
			case <-s.ctx.Done():
				return nil
			default:
				continue
			}
		}
		
		go s.handleConnection(conn)
	}
}

func (s *GameServer) handleConnection(conn net.Conn) {
	defer conn.Close()
	
	// Read headers for role information
	headers := make(map[string]string)
	scanner := bufio.NewScanner(conn)
	
	for scanner.Scan() {
		line := scanner.Text()
		if line == "" {
			break
		}
		
		parts := strings.SplitN(line, ":", 2)
		if len(parts) == 2 {
			headers[strings.TrimSpace(parts[0])] = strings.TrimSpace(parts[1])
		}
	}
	
	username := headers["X-Username"]
	if username == "" {
		conn.Write([]byte("Username required\n"))
		return
	}
	
	roleStr := headers["X-Role"]
	role := RoleUser
	
	switch strings.ToLower(roleStr) {
	case "admin":
		role = RoleAdmin
	case "moderator":
		role = RoleModerator
	case "owner":
		role = RoleOwner
	}
	
	s.addClient(conn, username, role)
}

